/**
 * Type of this filter, determines which other fields are present.Can be any of:
 * * `eq`,
 * * `ne`,
 * * `prefix`,
 * * `in`,
 * * `remainder`,
 * * `suffix`,
 * * `contains`,
 * * `existsKey`,
 * * `series`,
 * * `or`,
 * * `and`,
 * * `not`,
 * * `ge`,
 * * `gt`,
 * * `le`,
 * * `lt`,
 * * `otherwise`.
 *
 * @deprecated Use literal values.
 */
export declare enum FilterType {
    And = "and",
    Contains = "contains",
    Eq = "eq",
    ExistsKey = "existsKey",
    Ge = "ge",
    Gt = "gt",
    In = "in",
    Le = "le",
    Lt = "lt",
    Ne = "ne",
    Not = "not",
    Or = "or",
    Otherwise = "otherwise",
    Prefix = "prefix",
    Remainder = "remainder",
    Series = "series",
    Suffix = "suffix"
}
